const esc = s => s;
function renderBlocks(blocks){
  return blocks.map(b=>{
    if(b.gist) return `<p class="gist reveal">${esc(b.gist)}</p>`;
    if(b.p) return `<p class="body-t reveal">${esc(b.p)}</p>`;
    if(b.note) return `<p class="note reveal detail">${esc(b.note)}</p>`;
    if(b.counters) return `<div class="counters reveal">`+b.counters.map(c=>
      `<div class="counter"><div class="n" data-count="${esc(c.n)}">0</div><div class="l">${esc(c.label)}</div></div>`).join("")+`</div>`;
    if(b.project){
      const p=b.project;
      if(p.soon){
        const note = p.meta ? `<div class="proj-body"><p class="body-t">${esc(p.meta)}</p></div>` : "";
        return `<article class="project soon${p.meta?" has-note":""} reveal"><div class="proj-head"><div><p class="proj-no">${esc(p.no)}</p><h3 class="proj-title">${esc(p.title)}</h3></div><span class="badge">${esc(p.badge)}</span></div>${note}</article>`;
      }
      const img = p.image ? `<div class="proj-img"><img src="${esc(p.image)}" alt=""></div>`
                          : `<div class="proj-img detail">${esc(p.imagePlaceholder)}</div>`;
      return `<article class="project reveal">
        <div class="proj-head"><div><p class="proj-no">${esc(p.no)}</p><h3 class="proj-title">${esc(p.title)}</h3></div><span class="badge">${esc(p.badge)}</span></div>
        <div class="proj-body">
          <p class="proj-meta">${esc(p.meta)}</p>
          <p class="body-t">${esc(p.summary)}</p>
          ${img}
          <a class="proj-cta" href="${esc(p.link)}">${esc(p.linkText)} →</a>
        </div></article>`;
    }
    return "";
  }).join("");
}
