const skimBtn=document.getElementById("skim");
skimBtn.addEventListener("click",()=>{
  const on=document.body.classList.toggle("skim");
  skimBtn.setAttribute("aria-pressed",on);
  skimBtn.textContent=on?"full mode":"skim mode";
});
requestAnimationFrame(()=>skimBtn.classList.add("attn"));
const clearAttn=()=>skimBtn.classList.remove("attn");
skimBtn.addEventListener("click",clearAttn,{once:true});
skimBtn.addEventListener("mouseenter",clearAttn,{once:true});
skimBtn.addEventListener("focus",clearAttn,{once:true});
setTimeout(clearAttn,7000);
const bar=document.querySelector("#progress b"),readout=document.getElementById("readout"),complete=document.getElementById("complete");
addEventListener("scroll",()=>{
  const h=document.documentElement,max=h.scrollHeight-h.clientHeight,
        pc=max>0?Math.min(100,Math.round(h.scrollTop/max*100)):100;
  bar.style.width=pc+"%";readout.textContent="read "+pc+"%";
  if(pc>=96)complete.classList.add("on");
},{passive:true});
const io=new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting)e.target.classList.add("in")}),{threshold:.15});
document.querySelectorAll(".reveal").forEach(el=>io.observe(el));
const secIO=new IntersectionObserver(es=>es.forEach(e=>{
  if(e.isIntersecting){
    const li=document.querySelector(`.index li[data-sec="${e.target.id}"]`);
    if(li)li.classList.add("done");
  }}),{threshold:.4});
document.querySelectorAll("section").forEach(s=>secIO.observe(s));
const cIO=new IntersectionObserver(es=>es.forEach(e=>{
  if(!e.isIntersecting)return;
  const el=e.target,target=el.dataset.count,num=parseInt(target)||0,suffix=target.replace(/^[0-9]+/,"");
  let cur=0;const step=()=>{cur++;el.textContent=(num?cur:target.charAt(0))+ (cur>=num?suffix:"");
    if(cur<num)requestAnimationFrame(step);else el.textContent=target;};
  num?step():el.textContent=target;
  cIO.unobserve(el);
}),{threshold:.6});
document.querySelectorAll("[data-count]").forEach(el=>cIO.observe(el));
